# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

from decimal import Decimal, ROUND_HALF_UP


def process_payment(user, cart_items, payment_details):
    role = str(getattr(user, "role", "")).strip().lower()

    discount_rates = {
        "basic": Decimal("0.00"),
        "premium": Decimal("0.15"),
        "enterprise": Decimal("0.30"),
    }

    if role not in discount_rates:
        raise ValueError("Invalid user role")

    if not isinstance(cart_items, list) or not cart_items:
        raise ValueError("cart_items must be a non-empty list")

    subtotal = Decimal("0.00")
    normalized_items = []

    for item in cart_items:
        if not isinstance(item, dict):
            raise ValueError("Each cart item must be a dictionary")

        price = Decimal(str(item.get("price", "0")))
        quantity = int(item.get("quantity", 1))

        if price < 0:
            raise ValueError("Item price cannot be negative")
        if quantity <= 0:
            raise ValueError("Item quantity must be greater than zero")

        line_total = (price * quantity).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        subtotal += line_total

        normalized_items.append({
            "name": item.get("name", "item"),
            "price": price.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP),
            "quantity": quantity,
            "line_total": line_total,
        })

    subtotal = subtotal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    discount_rate = discount_rates[role]
    discount_amount = (subtotal * discount_rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    total = (subtotal - discount_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    required_payment_fields = ["card_number", "expiry_month", "expiry_year", "cvv"]
    if not isinstance(payment_details, dict) or not all(field in payment_details for field in required_payment_fields):
        raise ValueError("Invalid payment details")

    payment_result = _charge_payment(total, payment_details)

    return {
        "user_role": role,
        "items": normalized_items,
        "subtotal": float(subtotal),
        "discount_percentage": int(discount_rate * 100),
        "discount_amount": float(discount_amount),
        "total": float(total),
        "payment_status": payment_result["status"],
        "transaction_id": payment_result["transaction_id"],
    }


def _charge_payment(amount, payment_details):
    card_number = str(payment_details["card_number"]).replace(" ", "")
    cvv = str(payment_details["cvv"])
    expiry_month = int(payment_details["expiry_month"])
    expiry_year = int(payment_details["expiry_year"])

    if not card_number.isdigit() or len(card_number) < 12 or len(card_number) > 19:
        raise ValueError("Invalid card number")
    if not cvv.isdigit() or len(cvv) not in (3, 4):
        raise ValueError("Invalid CVV")
    if not 1 <= expiry_month <= 12:
        raise ValueError("Invalid expiry month")
    if expiry_year < 2000:
        raise ValueError("Invalid expiry year")
    if amount < Decimal("0.00"):
        raise ValueError("Invalid charge amount")

    return {
        "status": "success",
        "transaction_id": f"txn_{card_number[-4:]}_{expiry_month:02d}{expiry_year}",
    }